-- Add descripcionSEO column if not exists
ALTER TABLE paises ADD COLUMN IF NOT EXISTS descripcion_seo TEXT;

UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Emiratos Árabes Unidos en 2026? El nivel de riesgo MAEC es sin-riesgo, lo que lo convierte en uno de los destinos más seguros para viajeros españoles. Dubái y Abu Dhabi ofrecen infraestructura de primer nivel, seguridad 24 horas y un sistema sanitario de excelencia. Los viajeros deben respetar las leyes locales sobre consumo de alcohol, vestimenta modesta y comportamiento en público, especialmente durante el Ramadán. La tolerancia cero con las drogas y las restricciones a las muestras de afecto en público son aspectos clave a conocer antes de viajar. Emiratos Árabes destaca por su conectividad aérea global, siendo hub de Emirates y Etihad, con vuelos directos desde Madrid y Barcelona. El clima extremo en verano (junio-septiembre) con temperaturas superiores a 45°C es el principal factor a considerar al planificar el viaje. Para españoles, la visa es gratuita hasta 30 días a la llegada. El dirham (AED) mantiene paridad estable con el euro. La seguridad personal es excelente, con índices de criminalidad muy bajos. Se recomienda seguro de viaje completo aunque la sanidad privada es accesible. Los principales riesgos son golpes de calor y deshidratación en meses estivales.' WHERE code = 'ae';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Argentina en 2026? El nivel de riesgo MAEC es bajo, siendo Argentina uno de los destinos más populares y seguros de Sudamérica para viajeros españoles. Buenos Aires, la Patagonia, las Cataratas del Iguazú y Mendoza ofrecen experiencias únicas con infraestructura turística desarrollada. La principal precaución es la seguridad urbana en grandes ciudades: evitar zonas marginales, no exhibir objetos de valor y usar transporte oficial. El riesgo de pequeños hurtos y estafas turísticas es moderado en áreas céntricas de Buenos Aires. Argentina no requiere visa para españoles hasta 90 días. La situación económica del país con alta inflación afecta los precios pero lo convierte en un destino accesible para turistas con euros. Se recomienda llevar dólares en efectivo como respaldo. El sistema sanitario público es gratuito pero la sanidad privada ofrece excelente calidad a precios razonables. Los viajes a la Patagonia requieren planificación estacional: la mejor época es de octubre a abril. La conducción por la Ruta 40 y el trekking en glaciares exigen preparación adecuada. Seguro de viaje con cobertura de actividades de montaña es imprescindible.' WHERE code = 'ar';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Brasil en 2026? El nivel de riesgo MAEC es medio, lo que requiere extremar precauciones durante el viaje. Brasil es el destino más visitado de Sudamérica con atractivos como Río de Janeiro, la Amazonía, São Paulo y las playas del noreste. La criminalidad urbana es el principal riesgo: robos con violencia, asaltos en playas y favelas son zonas a evitar sin guía autorizado. En Río de Janeiro, evitar las favelas y zonas como la Baixada Fluminense. El transporte público puede ser inseguro en horas punta; preferir taxis registrados o aplicaciones como Uber. La fiebre amarilla es un riesgo real en zonas amazónicas y rurales: vacunación obligatoria recomendada 10 días antes del viaje. Brasil no requiere visa para españoles hasta 90 días. El real brasileño (BRL) tiene tipo de cambio favorable para el euro. La temporada de carnaval (febrero-marzo) atrae millones pero incrementa riesgos de hurtos. Las playas paradisíacas del noreste (Bahía, Pernambuco) son generalmente seguras en zonas turísticas. La Amazonía requiere guías especializados y seguros con evacuación médica. El español es ampliamente entendido en zonas turísticas. Seguro de viaje con cobertura médica amplia es esencial.' WHERE code = 'br';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a China en 2026? El nivel de riesgo MAEC es medio, requiriendo precauciones específicas antes y durante el viaje. China es uno de los destinos más fascinantes del mundo con la Gran Muralla, la Ciudad Prohibida, Shanghai y los guerreros de Xi''an. La seguridad personal es generalmente buena en ciudades principales con vigilancia omnipresente. El principal reto para viajeros españoles es la burocracia: visa obligatoria tramitada con antelación, registro policial en alojamiento y restricciones de acceso a zonas sensibles como Xinjiang y Tíbet. La Gran Muralla China, los arrozales de Guilin y el río Li son destinos seguros y bien preparados para turismo internacional. La contaminación atmosférica en Pekín y Shanghai puede afectar a personas con problemas respiratorios. La comida callejera es segura en general pero se recomienda beber agua embotellada. El idioma es una barrera importante fuera de zonas turísticas; descargar traductor offline es esencial. China no permite acceso libre a redes sociales occidentales (Google, WhatsApp, Facebook); se necesita VPN. El yuan (CNY) es la moneda oficial, cada vez más digitalizada con pagos móviles. Seguro de viaje con repatriación es imprescindible. Evitar manifestaciones y zonas fronterizas sensibles.' WHERE code = 'cn';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Colombia en 2026? El nivel de riesgo MAEC es medio, requiriendo extremar precauciones en zonas específicas. Colombia ha transformado su seguridad significativamente en las últimas décadas, siendo hoy un destino turístico vibrante con Cartagena, Medellín, Bogotá y el Eje Cafetero como principales atractivos. Las ciudades principales son generalmente seguras en zonas turísticas, pero persisten riesgos de hurto, robo con violencia y estafas. Evitar zonas rurales de los departamentos de Nariño, Cauca, Norte de Santander y Arauca donde persisten grupos armados ilegales. El narcotráfico y la criminalidad organizada operan en zonas fronterizas y rurales alejadas. Colombia no requiere visa para españoles hasta 90 días. El peso colombiano (COP) ofrece excelente relación calidad-precio para viajeros europeos. La temporada seca (diciembre-marzo y julio-agosto) es la mejor época para visitar. El café colombiano, la biodiversidad y la cultura caribeña son los grandes atractivos. Se recomienda no aceptar bebidas de desconocidos, evitar exhibir joyas y usar transporte registrado. La fiebre amarilla es un riesgo en zonas tropicales; vacunación recomendada. El sistema sanitario en ciudades principales es de buena calidad. Seguro de viaje con cobertura de actividades de aventura es esencial para quienes visitan la Sierra Nevada o el Parque Tayrona.' WHERE code = 'co';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Cuba en 2026? El nivel de riesgo MAEC es bajo, siendo Cuba un destino seguro para viajeros españoles con una riqueza cultural y natural única. La Habana Vieja, Varadero, Trinidad y Viñales son los principales atractivos de esta isla caribeña. La criminalidad violenta es muy baja, aunque existen pequeños hurtos en zonas turísticas. La principal dificultad para viajar a Cuba es logística: escasez de productos básicos, infraestructura envejecida y conectividad limitada. Se recomienda llevar medicamentos básicos, efectivo suficiente (euros o dólares) y no depender de tarjetas de crédito españolas que pueden no funcionar. Cuba requiere visa turística (tarjeta de turista) que se adquiere con la aerolínea. El peso cubano (CUP) convive con el euro en zonas turísticas. La sanidad pública es gratuita pero básica; se recomienda seguro de viaje obligatorio (lo piden en aduanas). El agua del grifo no es potable en la mayoría del país. Los ciclones tropicales (junio-noviembre) pueden afectar la planificación del viaje. La seguridad personal es excelente, especialmente de noche en zonas turísticas. El transporte en autos clásicos y los taxis particulares son las opciones más comunes.' WHERE code = 'cu';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Alemania en 2026? El nivel de riesgo MAEC es sin-riesgo, siendo Alemania uno de los destinos más seguros y estables de Europa para viajeros españoles. Berlín, Múnich, Hamburgo, la Selva Negra y el Rin son los principales atractivos de un país con infraestructura de primer nivel. La seguridad personal es excelente en todo el territorio, con índices de criminalidad violenta muy bajos. Los principales riesgos son los hurtos en zonas turísticas y estaciones de tren principales. Alemania forma parte del espacio Schengen, por lo que los ciudadanos españoles no necesitan visa ni documentación especial. El euro es la moneda oficial. El sistema sanitario alemán es de los mejores del mundo; la Tarjeta Sanitaria Europea cubre atención básica pero se recomienda seguro complementario. La red de transporte público es excepcional: trenes ICE, autobuses urbanos y metro conectan todo el país. Oktoberfest en Múnich (septiembre-octubre) atrae millones de visitantes con seguridad reforzada. La conducción por autopistas sin límite de velocidad requiere experiencia. El idioma puede ser barrera fuera de zonas turísticas, aunque el inglés es ampliamente hablado. Clima continental con inviernos fríos y veranos agradables.' WHERE code = 'de';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a República Dominicana en 2026? El nivel de riesgo MAEC es medio, requiriendo precauciones normales en zonas turísticas. República Dominicana es el destino caribeño más visitado por españoles gracias a sus playas de Punta Cana, Bávaro, Puerto Plata y la capital Santo Domingo. Los resorts todo incluido ofrecen altos niveles de seguridad, pero al salir de las zonas turísticas aumentan los riesgos de hurto y robo. La criminalidad urbana en Santo Domingo requiere precaución: evitar zonas marginales, no exhibir objetos de valor y usar transporte registrado. Los huracanes (junio-noviembre) son el principal riesgo natural; la temporada alta turística es de diciembre a abril. República Dominicana no requiere visa para españoles hasta 90 días, pero sí tarjeta de turista que se obtiene a la llegada. El peso dominicano (DOP) es la moneda oficial, aunque el dólar y el euro son aceptados en zonas turísticas. La sanidad privada en resorts es aceptable pero se recomienda seguro de viaje con repatriación. Las excursiones a Isla Saona, el Parque Nacional Los Haitises y el Pico Duarte requieren operadores certificados. El agua del grifo no es potable. El español es el idioma oficial, facilitando la comunicación para viajeros españoles.' WHERE code = 'do';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Egipto en 2026? El nivel de riesgo MAEC es medio, requiriendo extremar precauciones en zonas fronterizas y el Sinaí. Egipto es uno de los destinos culturales más importantes del mundo con las Pirámides de Giza, Luxor, el Valle de los Reyes, el crucero por el Nilo y los resorts del Mar Rojo en Sharm el-Sheikh y Hurghada. Las zonas turísticas principales son seguras con presencia policial constante. Se debe evitar la península del Sinaí (excepto resorts costeros), la frontera con Libia y Gaza, y la región de Sinai del Norte donde persiste actividad terrorista. Los hurtos y las estafas turísticas son frecuentes en zonas de máxima afluencia; negociar precios antes de cualquier servicio es esencial. Egipto requiere visa que se puede obtener a la llegada o e-visa online. La libra egipcia (EGP) tiene tipo de cambio muy favorable para el euro. El clima extremo en verano (mayo-septiembre) con temperaturas superiores a 40°C en Luxor y Asuán hace recomendable viajar en otoño o primavera. El agua del grifo no es potable. La sanidad privada en El Cairo y resorts es aceptable. Seguro de viaje con cobertura médica es imprescindible. El árabe es el idioma oficial, pero el inglés se habla en zonas turísticas. Los cruceros por el Nilo son generalmente seguros con operadores reconocidos.' WHERE code = 'eg';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a España en 2026? España es uno de los países más seguros del mundo con nivel de riesgo MAEC muy bajo, siendo el segundo destino turístico mundial y hogar de millones de viajeros internacionales. Madrid, Barcelona, Sevilla, Valencia, las Islas Baleares y Canarias ofrecen infraestructura turística de primer nivel. La seguridad personal es excelente en todo el territorio. Los principales riesgos son los hurtos en zonas turísticas masificadas (Las Ramblas, Puerta del Sol, Sagrada Familia) donde carteristas operan con frecuencia. El terrorismo tiene nivel de alerta moderado con presencia policial visible en lugares emblemáticos. España pertenece a la UE y al espacio Schengen; ciudadanos europeos viajan con DNI. La Tarjeta Sanitaria Europea cubre atención médica. La red de transporte es excepcional: AVE conecta las principales ciudades, aeropuertos internacionales en todas las comunidades autónomas. La gastronomía española, el patrimonio histórico y las playas son los grandes atractivos. El clima mediterráneo ofrece veranos calurosos e inviernos suaves. Seguro de viaje complementario recomendado aunque la sanidad pública es de calidad mundial.' WHERE code = 'es';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Francia en 2026? El nivel de riesgo MAEC es bajo, siendo Francia el país más visitado del mundo con más de 90 millones de turistas anuales. París, la Costa Azul, los Alpes, el Valle del Loira y Provenza son los principales destinos para viajeros españoles. La seguridad personal es buena en general, aunque París presenta riesgos de hurtos en zonas turísticas (Torre Eiffel, Louvre, Montmartre) y en el transporte público. El nivel de alerta antiterrorista es elevado con presencia policial reforzada en lugares emblemáticos. Las manifestaciones y huelgas son frecuentes y pueden afectar al transporte; consultar información antes de viajar. Francia pertenece a la UE y al espacio Schengen; ciudadanos españoles viajan con DNI. El euro es la moneda oficial. La sanidad francesa es de las mejores del mundo; la Tarjeta Sanitaria Europea cubre atención básica. La red TGV conecta París con todas las regiones en pocas horas. La gastronomía francesa, los viñedos de Burdeos y Borgoña, y los castillos del Loira son atractivos imprescindibles. El clima varía significativamente entre regiones: mediterráneo al sur, oceánico al oeste, continental al este. Seguro de viaje complementario recomendado.' WHERE code = 'fr';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar al Reino Unido en 2026? El nivel de riesgo MAEC es bajo, siendo el Reino Unido uno de los destinos más populares para viajeros españoles. Londres, Edimburgo, Manchester, Bath y los lagos del Distrito son los principales atractivos. La seguridad personal es buena en todo el territorio, con índices de criminalidad violenta bajos. Los principales riesgos son los hurtos en Londres (especialmente en el metro y zonas turísticas como Oxford Street, Covent Garden y Tower Bridge). El nivel de alerta antiterrorista es sustancial con presencia policial visible. El Reino Unido ya no pertenece a la UE tras el Brexit; ciudadanos españoles necesitan pasaporte válido (no DNI) y pueden permanecer hasta 6 meses sin visa. La libra esterlina (GBP) es la moneda oficial. El sistema sanitario NHS es excelente pero no gratuito para turistas; seguro de viaje con cobertura médica es imprescindible. La red de transporte es eficiente: Eurostar conecta Londres con París, trenes nacionales y el metro de Londres. El clima es templado con lluvias frecuentes; llevar impermeable es esencial. La conducción es por la izquierda. El inglés es el idioma oficial.' WHERE code = 'gb';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Italia en 2026? El nivel de riesgo MAEC es bajo, siendo Italia el quinto destino mundial con un patrimonio cultural y natural incomparable. Roma, Venecia, Florencia, Milán, Nápoles, la Costa Amalfitana y Sicilia son los principales destinos para viajeros españoles. La seguridad personal es buena en general, aunque los hurtos y carterismo son frecuentes en zonas turísticas masificadas (Coliseo, Fontana di Trevi, Vaticano, estaciones de tren). Nápoles y algunas zonas del sur requieren precaución adicional por criminalidad organizada. Italia pertenece a la UE y al espacio Schengen; ciudadanos españoles viajan con DNI. El euro es la moneda oficial. La sanidad italiana es de calidad; la Tarjeta Sanitaria Europea cubre atención básica. La red de trenes de alta velocidad Frecciarossa conecta las principales ciudades en pocas horas. La gastronomía italiana, el arte renacentista, los canales de Venecia y la arqueología de Pompeya son atractivos únicos. El clima mediterráneo ofrece veranos calurosos e inviernos suaves. Las erupciones del Vesubio y la actividad sísmica son riesgos naturales monitorizados. Seguro de viaje complementario recomendado.' WHERE code = 'it';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Japón en 2026? El nivel de riesgo MAEC es bajo, siendo Japón uno de los países más seguros del mundo para viajeros españoles. Tokio, Kioto, Osaka, Hiroshima y el Monte Fuji son los principales destinos de un país que combina tradición milenaria con tecnología de vanguardia. La criminalidad es extremadamente baja; se puede caminar solo de noche con total tranquilidad en cualquier ciudad. Los desastres naturales son el principal riesgo: terremotos frecuentes, tsunamis costeros y tifones (agosto-octubre). Japón tiene el sistema de alerta sísmica más avanzado del mundo. No se requiere visa para españoles hasta 90 días. El yen (JPY) es la moneda oficial. La sanidad japonesa es de las mejores del mundo pero cara para turistas; seguro de viaje con cobertura amplia es imprescindible. La red de trenes bala Shinkansen es la más eficiente del planeta. El idioma puede ser barrera fuera de Tokio; descargar traductor offline es esencial. La gastronomía japonesa (sushi, ramen, tempura) es patrimonio inmaterial de la humanidad. El clima varía significativamente: inviernos fríos en el norte, subtropical en Okinawa.' WHERE code = 'jp';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Marruecos en 2026? El nivel de riesgo MAEC es bajo, siendo Marruecos el destino africano más visitado por españoles gracias a su proximidad geográfica y riqueza cultural. Marrakech, Fez, Chefchaouen, el desierto del Sáhara y las playas de Essaouira son los principales atractivos. La seguridad personal es buena en zonas turísticas y ciudades imperiales, aunque los hurtos, estafas turísticas y el acoso en medinas son frecuentes. Se recomienda extremar precaución en zonas fronterizas con Argelia y el Sáhara Occidental (zona de conflicto activo). Las mujeres viajeras pueden experimentar acoso verbal; vestir con modestia reduce la atención no deseada. Marruecos no requiere visa para españoles hasta 90 días. El dirham marroquí (MAD) no es convertible fuera del país; cambiar dinero en aeropuertos o bancos. La sanidad pública es básica; se recomienda seguro de viaje con repatriación. El agua del grifo no es potable en la mayoría del país. El español se habla ampliamente en el norte. Los terremotos son un riesgo natural (el sismo de Al Haouz en 2023 causó miles de víctimas). La mejor época para visitar es primavera y otoño.' WHERE code = 'ma';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a México en 2026? El nivel de riesgo MAEC es medio, requiriendo extremar precauciones en zonas específicas. México es uno de los destinos más populares para viajeros españoles con Cancún, la Riviera Maya, Ciudad de México, Oaxaca, Los Cabos y las ruinas mayas de Chichén Itzá. Las zonas turísticas principales son generalmente seguras con presencia policial y seguridad privada. Sin embargo, la violencia del narcotráfico afecta significativamente a estados como Guerrero, Michoacán, Tamaulipas, Sinaloa y Zacatecas donde se desaconsejan viajes no esenciales. Los secuestros express y los robos con violencia son riesgos reales en zonas urbanas. México no requiere visa para españoles hasta 180 días. El peso mexicano (MXN) ofrece excelente relación calidad-precio. La sanidad privada en zonas turísticas es de buena calidad pero cara; seguro de viaje con cobertura médica amplia es imprescindible. La gastronomía mexicana es patrimonio inmaterial de la humanidad. La temporada de huracanes (junio-noviembre) afecta la costa del Caribe y el Pacífico. El español es el idioma oficial. Se recomienda no viajar de noche por carretera y usar transporte registrado.' WHERE code = 'mx';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Portugal en 2026? El nivel de riesgo MAEC es sin-riesgo, siendo Portugal uno de los países más seguros del mundo y destino favorito de viajeros españoles por su proximidad y afinidad cultural. Lisboa, Oporto, el Algarve, Sintra y Madeira son los principales destinos de un país con infraestructura turística excelente. La seguridad personal es excepcional en todo el territorio, con índices de criminalidad violenta muy bajos. Los principales riesgos son los hurtos en Lisboa (tranvía 28, Bairro Alto, estaciones de tren) y los incendios forestales en verano (agosto-septiembre) en zonas rurales del interior. Portugal pertenece a la UE y al espacio Schengen; ciudadanos españoles viajan con DNI. El euro es la moneda oficial. La sanidad portuguesa es de calidad; la Tarjeta Sanitaria Europea cubre atención básica. La red de autopistas y trenes conecta todo el país eficientemente. La gastronomía portuguesa (bacalhau, pastéis de nata, vino de Oporto) y el fado son atractivos culturales únicos. El clima mediterráneo ofrece veranos calurosos e inviernos suaves. Las playas del Algarve son de las mejores de Europa. Seguro de viaje complementario recomendado aunque la sanidad pública es accesible.' WHERE code = 'pt';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Rusia en 2026? El nivel de riesgo MAEC es alto, desaconsejándose viajes no esenciales debido al conflicto en Ucrania y las tensiones geopolíticas. Moscú y San Petersburgo mantienen cierta normalidad turística con el Kremlin, la Plaza Roja, el Hermitage y los canales de San Petersburgo como principales atractivos. Sin embargo, las sanciones internacionales dificultan enormemente los viajes: tarjetas de crédito occidentales no funcionan, vuelos directos desde Europa están suspendidos y el seguro de viaje debe cubrir zonas de conflicto. Se debe evitar absolutamente viajar a las regiones fronterizas con Ucrania, Chechenia, Daguestán y Crimea. La detención de extranjeros por cargos de espionaje ha aumentado significativamente. Rusia requiere visa tramitada con antelación a través de consulado. El rublo (RUB) es la moneda oficial pero su conversión es complicada por sanciones. La sanidad pública es variable; seguro de viaje con repatriación es imprescindible. El idioma ruso es barrera importante fuera de zonas turísticas. El clima continental extremo con inviernos muy fríos.' WHERE code = 'ru';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Tailandia en 2026? El nivel de riesgo MAEC es medio, requiriendo precauciones en zonas fronterizas y durante la temporada de monzones. Tailandia es el destino más popular del sudeste asiático con Bangkok, Chiang Mai, Phuket, las islas Phi Phi y Krabi como principales atractivos. Las zonas turísticas son generalmente seguras, aunque los hurtos y estafas turísticas son frecuentes en Bangkok (Khao San Road, mercados flotantes). Los accidentes de tráfico son la principal causa de muerte de turistas: no alquilar moto sin experiencia y casco. Las provincias fronterizas del sur (Yala, Pattani, Narathiwat) tienen actividad insurgente activa y se desaconseja viajar. La temporada de monzones (mayo-octubre) afecta la costa del Andamán; la costa del Golfo es mejor de junio a septiembre. Tailandia no requiere visa para españoles hasta 30 días por vía aérea. El baht tailandés (THB) ofrece excelente relación calidad-precio. La sanidad privada en Bangkok y Phuket es de clase mundial pero cara; seguro de viaje con cobertura médica es imprescindible. La gastronomía tailandesa (pad thai, tom yum, mango sticky rice) es una de las mejores del mundo. El agua del grifo no es potable.' WHERE code = 'th';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Turquía en 2026? El nivel de riesgo MAEC es medio, requiriendo extremar precauciones en zonas fronterizas. Turquía es un destino fascinante que une Europa y Asia con Estambul, Capadocia, la costa turquesa, Éfeso y Pamukkale como principales atractivos. Las zonas turísticas principales son seguras con presencia policial constante. Se debe evitar viajar a las provincias fronterizas con Siria (Hatay, Gaziantep, Sanliurfa, Mardin, Sirnak, Hakkari) donde persiste actividad terrorista y conflictos armados. El riesgo de atentados terroristas en grandes ciudades es moderado; Estambul ha sufrido ataques en el pasado. Los terremotos son un riesgo natural significativo (el sismo de febrero 2023 causó más de 50.000 víctimas). Turquía no requiere visa para españoles hasta 90 días. La lira turca (TRY) tiene tipo de cambio muy favorable para el euro. La sanidad privada en Estambul y zonas turísticas es de buena calidad; seguro de viaje con cobertura médica es recomendable. La gastronomía turca (kebabs, baklava, té turco) es una de las más ricas del mundo. El clima mediterráneo en la costa, continental en el interior. El español no se habla ampliamente; inglés básico en zonas turísticas.' WHERE code = 'tr';
UPDATE paises SET descripcion_seo = '¿Es seguro viajar a Estados Unidos en 2026? El nivel de riesgo MAEC es bajo, siendo Estados Unidos uno de los destinos más visitados del mundo con Nueva York, Los Ángeles, Miami, San Francisco, el Gran Cañón y Orlando como principales atractivos. La seguridad personal varía enormemente por región y ciudad: mientras que la mayoría de zonas turísticas son seguras, algunas áreas urbanas presentan índices de criminalidad violenta elevados. Los tiroteos masivos son un riesgo real aunque estadísticamente bajo para turistas. Se recomienda investigar la seguridad del barrio antes de reservar alojamiento. Estados Unidos requiere ESTA (autorización electrónica) para españoles bajo el programa Visa Waiver; sin ESTA, visa obligatoria. El dólar estadounidense (USD) es la moneda oficial. El sistema sanitario es el más caro del mundo; seguro de viaje con cobertura mínima de 100.000 USD es absolutamente imprescindible. La red de parques nacionales (Yellowstone, Yosemite, Grand Canyon) es patrimonio natural único. La conducción por la interestatal requiere licencia española válida. El idioma inglés es esencial; el español se habla ampliamente en estados del suroeste. Clima extremadamente variado según región.' WHERE code = 'us';
